// Rotate post type based on day of week
// Mon = pain_point, Wed = case_study, Fri = tips
const dayOfWeek = new Date().getDay();

const postTypes = {
  1: 'pain_point',
  3: 'case_study',
  5: 'tips'
};

const type = postTypes[dayOfWeek] || 'pain_point';

const prompts = {
  pain_point: {
    type: 'pain_point',
    instruction: `Write a LinkedIn post (150-200 words) for AutoShop SMS AI targeting auto repair shop owners. Focus on the PAIN POINT of missed calls costing shops real revenue. Include a specific stat or scenario (e.g., "The average missed call costs an auto shop $250-$700 in lost repair revenue"). Tone: professional, empathetic, solution-oriented. Do NOT be salesy — educate first. End with a soft CTA mentioning autoshopsmsai.com. Use 2-3 relevant hashtags at the end. No emojis in the first line.`
  },
  case_study: {
    type: 'case_study',
    instruction: `Write a LinkedIn post (150-200 words) for AutoShop SMS AI in a case-study style. Share realistic stats about how AI-powered SMS booking helps auto repair shops (e.g., "Shops using automated SMS follow-up recover 35-40% of missed calls as booked appointments"). Use a narrative format — paint a before/after picture for a typical independent shop. Tone: credible, data-informed, conversational. End with a soft CTA mentioning autoshopsmsai.com. Use 2-3 relevant hashtags at the end. No emojis in the first line.`
  },
  tips: {
    type: 'tips',
    instruction: `Write a LinkedIn post (150-200 words) for AutoShop SMS AI offering practical advice to auto repair shop owners. Share 3 actionable tips about improving customer communication, reducing no-shows, or capturing more revenue from inbound calls. Tone: helpful, expert, peer-to-peer (as if one shop owner advising another). End with a soft mention of autoshopsmsai.com as a resource. Use 2-3 relevant hashtags at the end. No emojis in the first line.`
  }
};

return [{ json: prompts[type] }];

const resp = $input.first().json;
let postText = '';

if (resp.content && resp.content[0] && resp.content[0].text) {
  postText = resp.content[0].text.trim();
} else {
  throw new Error('Claude API returned unexpected response: ' + JSON.stringify(resp).slice(0, 500));
}

// Get post type from earlier node
const postType = $('Select Post Type').first().json.type;

return [{ json: { postText, postType, generatedAt: new Date().toISOString() } }];

const imageResp = $input.first().json;
const postData = $('Extract Post Text').first().json;

let imageUrl = '';
if (imageResp.data && imageResp.data[0] && imageResp.data[0].url) {
  imageUrl = imageResp.data[0].url;
} else {
  imageUrl = 'IMAGE_GENERATION_FAILED';
}

return [{ json: {
  postText: postData.postText,
  postType: postData.postType,
  imageUrl: imageUrl,
  generatedAt: postData.generatedAt,
  status: 'pending_review'
} }];

const data = $input.first().json;

const typeLabels = {
  pain_point: '🔴 Pain Point',
  case_study: '📊 Case Study',
  tips: '💡 Tips & Advice'
};

const preview = data.postText.length > 300 ? data.postText.slice(0, 300) + '...' : data.postText;

let msg = '📋 LINKEDIN POST READY FOR REVIEW\n\n';
msg += 'Type: ' + (typeLabels[data.postType] || data.postType) + '\n';
msg += 'Generated: ' + data.generatedAt + '\n\n';
msg += '--- POST PREVIEW ---\n';
msg += preview + '\n';
msg += '--- END PREVIEW ---\n\n';

if (data.imageUrl && data.imageUrl !== 'IMAGE_GENERATION_FAILED') {
  msg += '🖼 Image: ' + data.imageUrl + '\n\n';
} else {
  msg += '⚠️ Image generation failed — manual image needed\n\n';
}

msg += 'Reply APPROVE to post to LinkedIn\n';
msg += 'Reply SKIP to skip this post\n';
msg += 'Reply EDIT: <your changes> to request edits';

return [{ json: { chatId: '8747048300', text: msg, postText: data.postText, imageUrl: data.imageUrl, postType: data.postType } }];

const msg = $input.first().json;
const text = (msg.message?.text || '').trim().toUpperCase();

let action = 'ignore';

if (text === 'APPROVE') {
  action = 'approve';
} else if (text === 'SKIP') {
  action = 'skip';
} else if (text.startsWith('EDIT:')) {
  action = 'edit';
}

return [{ json: { action, rawText: msg.message?.text || '', chatId: msg.message?.chat?.id } }];

// Retrieve the most recent pending post from Google Sheets
// In production, this would read the latest 'pending_review' row
// For now, pass through with placeholder — the sheet lookup node should be wired here

const postText = $env.LINKEDIN_PENDING_POST || 'Post text not found — check Google Sheet';
const imageUrl = $env.LINKEDIN_PENDING_IMAGE || '';

return [{ json: {
  postText,
  imageUrl,
  visibility: 'PUBLIC'
} }];

const resp = $input.first().json;
const success = resp.id ? true : false;

let msg;
if (success) {
  msg = '✅ LinkedIn post published successfully!\nPost ID: ' + resp.id;
} else {
  msg = '❌ LinkedIn post FAILED\nError: ' + JSON.stringify(resp).slice(0, 500);
}

return [{ json: { chatId: '8747048300', text: msg, success } }];
